local OOOO0OOOO='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function O00OOO000(b)
    b=b:gsub('%s+','')
    b=b:gsub('[^'..OOOO0OOOO..'=]','')
    return (b:gsub('.', function(x)
        if x=='=' then return '' end
        local r,f='',(OOOO0OOOO:find(x,1,true)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x~=8 then return '' end
        local c=0
        for i=1,8 do if x:sub(i,i)=='1' then c=c+2^(8-i) end end
        return string.char(c)
    end))
end
local O0OOO00OO=O00OOO000(O0OOO000O)
local O000O0OOO=(bit32 and bit32.bxor) or function(a,b) return a ~ b end
